const allInputs = $input.all();
const config = $('Configuration').first().json;

const seoTerms = ['seo', 'keyword', 'ranking', 'backlink', 'serp', 'traffic',
  'search engine', 'search optim', 'rank track', 'domain', 'audit', 'content',
  'google', 'organic', 'link building', 'on-page', 'off-page', 'site speed',
  'crawl', 'index', 'digital marketing', 'competitor', 'analytics'];

const isSeoRelated = p =>
  seoTerms.some(t => (p || '').toLowerCase().includes(t));

const domainMap = [
  { label: config.your_domain + ' (your domain — target)', filterSeo: false },
  { label: config.your_domain + ' (your domain — brand)', filterSeo: false },
  { label: config.competitor_domain_1 + ' (competitor 1 — target)', filterSeo: true },
  { label: config.competitor_domain_1 + ' (competitor 1 — brand)', filterSeo: true },
  { label: config.competitor_domain_2 + ' (competitor 2 — target)', filterSeo: true },
  { label: config.competitor_domain_2 + ' (competitor 2 — brand)', filterSeo: true },
];

const sections = allInputs.map((input, idx) => {
  const info = domainMap[idx] || { label: 'domain ' + idx, filterSeo: true };
  let prompts = (input.json.prompts || []).map(function(p) { return p.prompt; }).filter(Boolean);
  if (info.filterSeo) {
    prompts = prompts.filter(function(p) { return isSeoRelated(p); });
  }
  if (!prompts.length) return null;
  return 'Domain: ' + info.label + '\nPrompts: ' + prompts.join(', ');
}).filter(Boolean);

return [{
  json: {
    prompt_data: sections.join('\n\n'),
    your_domain: config.your_domain,
    your_brand: config.your_brand,
    competitor_domain_1: config.competitor_domain_1,
    competitor_brand_1: config.competitor_brand_1,
    competitor_domain_2: config.competitor_domain_2,
    competitor_brand_2: config.competitor_brand_2
  }
}];

const data = $input.first().json;
const config = $('Configuration').first().json;

let parsed;
try {
  const content =
    data.output?.[0]?.content?.[0]?.text ||
    data.message?.content ||
    data.choices?.[0]?.message?.content ||
    '';
  const clean = content.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  return [{ json: { error: 'Failed to parse GPT response', raw: JSON.stringify(data) } }];
}

const topics = parsed.topics || [];

return topics.map(t => ({
  json: {
    topic: t.topic || '',
    winner: t.winner || '',
    [`${config.your_domain}_prompts`]: t.your_count || 0,
    [`${config.competitor_domain_1}_prompts`]: t.competitor_1_count || 0,
    [`${config.competitor_domain_2}_prompts`]: t.competitor_2_count || 0,
    insight: t.insight || '',
    top_prompts: (t.top_prompts || []).join(', '),
    overall_winner: parsed.overall_winner || '',
    summary: parsed.summary || '',
    date: new Date().toISOString().split('T')[0]
  }
}));
